using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class WeeklySummaryConfiguration : IEntityTypeConfiguration<WeeklySummary>{public void Configure(EntityTypeBuilder<WeeklySummary> builder){builder.ToTable("weekly_summaries");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("summary_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.AvgDifficulty).HasColumnType("decimal(3,2)");builder.Property(e => e.AvgHunger).HasColumnType("decimal(3,2)");builder.Property(e => e.AvgEnergy).HasColumnType("decimal(3,2)");builder.Property(e => e.AdherencePercent).HasColumnType("decimal(5,2)");builder.Property(e => e.WeightChangeKg).HasColumnType("decimal(5,2)");builder.Property(e => e.AiRecommendations).HasColumnType("jsonb");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.WeekStartDate }).IsUnique();}}
